using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollmentRequests = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, data structures, and the design of software and hardware systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Exploration of abstract structures, patterns, and quantitative reasoning from pure theory to applied problem-solving." },
            new() { Id = 3, Code = "PHYS", Name = "Physics", Description = "Investigation of matter, energy, and the fundamental forces that govern the natural world." },
            new() { Id = 4, Code = "ENG", Name = "English", Description = "Critical analysis of literature, rhetoric, and the craft of written and spoken communication." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "Examination of past events, civilizations, and societal transformations that shape the modern world." },
            new() { Id = 6, Code = "BIOL", Name = "Biology", Description = "Study of living organisms, their structure, function, evolution, and interactions with the environment." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor of Computer Science", Email = "achen@university.edu", Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 papers in top-tier conferences and holds three patents in natural language processing. She received her Ph.D. from MIT and has been teaching for 15 years." },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor of Computer Science", Email = "rmartinez@university.edu", Bio = "Dr. Martinez focuses on software engineering and distributed systems. Before joining academia, he spent a decade at leading tech companies. He is passionate about teaching clean code practices and system design." },
            new() { Id = 3, Name = "Dr. Sarah Williams", Title = "Professor of Mathematics", Email = "swilliams@university.edu", Bio = "Dr. Williams is an award-winning mathematician whose research spans abstract algebra and number theory. She has mentored over 20 doctoral students and is a fellow of the American Mathematical Society." },
            new() { Id = 4, Name = "Dr. James Park", Title = "Associate Professor of Mathematics", Email = "jpark@university.edu", Bio = "Dr. Park specializes in applied mathematics and statistics. His work on stochastic modeling has been applied in finance and epidemiology. He enjoys making complex mathematical concepts accessible to all students." },
            new() { Id = 5, Name = "Dr. Emily Thompson", Title = "Professor of Physics", Email = "ethompson@university.edu", Bio = "Dr. Thompson is an experimental physicist studying quantum optics. She has led research funded by the NSF and DOE, and her lab has produced breakthroughs in photonic quantum computing." },
            new() { Id = 6, Name = "Dr. Michael Brown", Title = "Associate Professor of Physics", Email = "mbrown@university.edu", Bio = "Dr. Brown researches astrophysics and cosmology. He has contributed to several space telescope projects and is known for his engaging lectures on the mysteries of the universe." },
            new() { Id = 7, Name = "Dr. Lisa Johnson", Title = "Professor of English", Email = "ljohnson@university.edu", Bio = "Dr. Johnson is a literary scholar specializing in 19th-century American literature and critical theory. She has authored three books and serves on the editorial board of two literary journals." },
            new() { Id = 8, Name = "Dr. David Kim", Title = "Associate Professor of History", Email = "dkim@university.edu", Bio = "Dr. Kim is a historian of East Asian studies with expertise in modern Japanese history. His recent book on post-war cultural transformation received the Bancroft Prize." },
            new() { Id = 9, Name = "Dr. Maria Garcia", Title = "Professor of Biology", Email = "mgarcia@university.edu", Bio = "Dr. Garcia is a molecular biologist studying gene expression and epigenetics. She leads a research group of 12 and has secured multiple NIH grants for her work on developmental biology." },
            new() { Id = 10, Name = "Dr. Kevin Wright", Title = "Associate Professor of Biology", Email = "kwright@university.edu", Bio = "Dr. Wright is an ecologist focused on conservation biology and biodiversity. He has conducted fieldwork on six continents and actively collaborates with wildlife conservation organizations." },
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Description = "A broad introduction to computer science covering computational thinking, basic programming in Python, data representation, and an overview of major subfields. No prior experience required.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Hall 201", MaxEnrollment = 120, IsFeatured = true, DepartmentId = 1, InstructorId = 1 },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures and Algorithms", Description = "In-depth study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques (divide-and-conquer, dynamic programming, greedy methods). Includes weekly programming assignments.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", Location = "Science Hall 305", MaxEnrollment = 60, IsFeatured = false, DepartmentId = 1, InstructorId = 1 },
            new() { Id = 3, Code = "CS 310", Title = "Software Engineering", Description = "Principles of software development including requirements analysis, design patterns, version control, testing, CI/CD pipelines, and agile methodologies. Students complete a semester-long team project.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", Location = "Tech Building 110", MaxEnrollment = 45, IsFeatured = true, DepartmentId = 1, InstructorId = 2 },
            new() { Id = 4, Code = "CS 450", Title = "Artificial Intelligence", Description = "Foundations of AI including search algorithms, knowledge representation, probabilistic reasoning, machine learning, and neural networks. Hands-on projects using modern AI frameworks.", Credits = 3, Schedule = "Tue/Thu 1:00–2:15 PM", Location = "Science Hall 201", MaxEnrollment = 40, IsFeatured = false, DepartmentId = 1, InstructorId = 1 },

            // Mathematics
            new() { Id = 5, Code = "MATH 101", Title = "Calculus I", Description = "Limits, continuity, derivatives, and integrals of single-variable functions. Applications to physics, engineering, and economics. Emphasis on both conceptual understanding and problem-solving skills.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", Location = "Math Building 100", MaxEnrollment = 150, IsFeatured = true, DepartmentId = 2, InstructorId = 3 },
            new() { Id = 6, Code = "MATH 201", Title = "Linear Algebra", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues and eigenvectors. Applications to computer graphics, data science, and engineering.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", Location = "Math Building 202", MaxEnrollment = 60, IsFeatured = false, DepartmentId = 2, InstructorId = 3 },
            new() { Id = 7, Code = "MATH 301", Title = "Probability and Statistics", Description = "Probability spaces, random variables, distributions, hypothesis testing, regression analysis, and Bayesian inference. Practical applications using R.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:15 PM", Location = "Math Building 105", MaxEnrollment = 50, IsFeatured = false, DepartmentId = 2, InstructorId = 4 },

            // Physics
            new() { Id = 8, Code = "PHYS 101", Title = "General Physics I", Description = "Mechanics, thermodynamics, and waves. Covers Newton's laws, energy conservation, rotational dynamics, oscillations, and sound. Includes a weekly laboratory section.", Credits = 4, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", Location = "Physics Lab 100", MaxEnrollment = 100, IsFeatured = true, DepartmentId = 3, InstructorId = 5 },
            new() { Id = 9, Code = "PHYS 201", Title = "Electromagnetism", Description = "Electric fields, magnetic fields, Maxwell's equations, electromagnetic waves, and optics. Mathematical treatment using vector calculus.", Credits = 4, Schedule = "Tue/Thu 2:00–3:30 PM", Location = "Physics Lab 200", MaxEnrollment = 50, IsFeatured = false, DepartmentId = 3, InstructorId = 5 },
            new() { Id = 10, Code = "PHYS 350", Title = "Quantum Mechanics", Description = "Wave-particle duality, the Schrödinger equation, quantum states, measurement theory, and applications to atomic and molecular systems.", Credits = 3, Schedule = "Mon/Wed 3:30–4:45 PM", Location = "Physics Lab 300", MaxEnrollment = 30, IsFeatured = false, DepartmentId = 3, InstructorId = 6 },

            // English
            new() { Id = 11, Code = "ENG 101", Title = "Composition and Rhetoric", Description = "Development of academic writing skills including argumentation, research methods, source evaluation, and revision strategies. Students produce a portfolio of essays.", Credits = 3, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", Location = "Humanities Hall 101", MaxEnrollment = 25, IsFeatured = false, DepartmentId = 4, InstructorId = 7 },
            new() { Id = 12, Code = "ENG 250", Title = "American Literature", Description = "Survey of American literary works from the colonial period to the present. Examines major authors, movements, and cultural contexts that shaped the American literary tradition.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:15 PM", Location = "Humanities Hall 205", MaxEnrollment = 35, IsFeatured = true, DepartmentId = 4, InstructorId = 7 },

            // History
            new() { Id = 13, Code = "HIST 101", Title = "World History to 1500", Description = "Survey of major civilizations and transformative events from antiquity through the late medieval period. Covers Mesopotamia, Egypt, Greece, Rome, China, the Islamic world, and the Americas.", Credits = 3, Schedule = "Tue/Thu 9:00–10:15 AM", Location = "Liberal Arts 300", MaxEnrollment = 80, IsFeatured = false, DepartmentId = 5, InstructorId = 8 },
            new() { Id = 14, Code = "HIST 320", Title = "Modern East Asia", Description = "Political, economic, and cultural history of China, Japan, and Korea from the 19th century to the present. Topics include imperialism, revolution, war, and rapid modernization.", Credits = 3, Schedule = "Mon/Wed 10:00–11:15 AM", Location = "Liberal Arts 310", MaxEnrollment = 40, IsFeatured = false, DepartmentId = 5, InstructorId = 8 },

            // Biology
            new() { Id = 15, Code = "BIOL 101", Title = "Introduction to Biology", Description = "Fundamental principles of biology including cell structure, genetics, evolution, ecology, and organismal diversity. Includes a weekly laboratory component.", Credits = 4, Schedule = "Mon/Wed/Fri 8:00–8:50 AM", Location = "Life Sciences 100", MaxEnrollment = 130, IsFeatured = true, DepartmentId = 6, InstructorId = 9 },
            new() { Id = 16, Code = "BIOL 220", Title = "Genetics", Description = "Mendelian and molecular genetics, gene regulation, genomics, and genetic engineering. Laboratory exercises include DNA extraction, PCR, and gel electrophoresis.", Credits = 4, Schedule = "Tue/Thu 1:00–2:30 PM", Location = "Life Sciences 210", MaxEnrollment = 45, IsFeatured = false, DepartmentId = 6, InstructorId = 9 },
            new() { Id = 17, Code = "BIOL 340", Title = "Ecology and Conservation", Description = "Population dynamics, community ecology, ecosystem processes, and conservation strategies. Includes field trips to local habitats and a group research project.", Credits = 3, Schedule = "Mon/Wed 2:00–3:15 PM", Location = "Life Sciences 305", MaxEnrollment = 35, IsFeatured = false, DepartmentId = 6, InstructorId = 10 },
        };

        // Wire up navigation properties
        foreach (var course in _courses)
        {
            course.Department = _departments.First(d => d.Id == course.DepartmentId);
            course.Instructor = _instructors.First(i => i.Id == course.InstructorId);
        }
    }

    public List<Department> GetDepartments() => _departments;

    public Department? GetDepartment(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetCourses() => _courses;

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Instructor.Name.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public Course? GetCourse(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public void SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        _enrollmentRequests.Add(request);
    }
}

