</div>

<section class="mb-5">
    <h2 class="mb-3">Featured Courses</h2>
    <div class="row">
        @foreach (var course in FeaturedCourses)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100 border-primary">
                    <div class="card-body">
                        <h5 class="card-title">@course.Code — @course.Title</h5>
                        <p class="card-text text-muted mb-1">@course.Department.Name · @course.Credits credits</p>
                        <p class="card-text">@Truncate(course.Description, 120)</p>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="courses/@course.Id" class="btn btn-outline-primary btn-sm">View Details</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

<section class="mb-5">
    <h2 class="mb-3">Departments</h2>
    <div class="row">
        @foreach (var dept in Departments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-body">
                        <h5 class="card-title">@dept.Name <span class="badge bg-secondary">@dept.Code</span></h5>
                        <p class="card-text">@dept.Description</p>
                    </div>
                    <div class="card-footer bg-transparent">
                        <a href="courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">Browse Courses</a>
                    </div>
                </div>
            </div>
        }
    </div>
</section>

<section class="mb-4 p-4 bg-light rounded">
    <h4>Ready to Enroll?</h4>
    <p>Submit your enrollment request to reserve your spot in a course.</p>
    <a href="enroll" class="btn btn-primary">Enrollment Request Form</a>
</section>

@code {
    private List<Models.Course> FeaturedCourses { get; set; } = new();
    private List<Models.Department> Departments { get; set; } = new();

    protected override void OnInitialized()
    {
        FeaturedCourses = CatalogService.GetFeaturedCourses();
        Departments = CatalogService.GetDepartments();
    }

    private static string Truncate(string text, int maxLength) =>
        text.Length <= maxLength ? text : text[..maxLength] + "…";
}

@page "/courses"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Courses — University Course Catalog</PageTitle>

<h1 class="mb-3">Course Catalog</h1>

<div class="row mb-4">
    <div class="col-md-6 mb-2">
        <input type="text" class="form-control" placeholder="Search by title, code, description, or instructor…"
               @bind="SearchTerm" @bind:event="oninput" @bind:after="ApplyFilters" />
    </div>
    <div class="col-md-4 mb-2">
        <select class="form-select" @bind="SelectedDepartmentId" @bind:after="ApplyFilters">
            <option value="0">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Id">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-2 mb-2">
        <button class="btn btn-outline-secondary w-100" @onclick="ClearFilters">Clear</button>
    </div>
</div>

@if (FilteredCourses.Count == 0)
{
    <div class="alert alert-info">No courses match your search criteria.</div>
}
else
{
    <p class="text-muted">Showing @FilteredCourses.Count course(s)</p>

    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Instructor</th>
                    <th>Schedule</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in FilteredCourses)
                {
                    <tr>
                        <td><strong>@course.Code</strong></td>
                        <td>@course.Title</td>
                        <td>@course.Department.Name</td>
                        <td>@course.Credits</td>
                        <td>@course.Instructor.Name</td>
                        <td>@course.Schedule</td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private string SearchTerm { get; set; } = string.Empty;
    private int SelectedDepartmentId { get; set; }
    private List<Department> Departments { get; set; } = new();
    private List<Course> FilteredCourses { get; set; } = new();

    protected override void OnInitialized()
    {
        Departments = CatalogService.GetDepartments();
        if (DepartmentId.HasValue)
            SelectedDepartmentId = DepartmentId.Value;
        ApplyFilters();
    }

    private void ApplyFilters()
    {
        FilteredCourses = CatalogService.SearchCourses(
            SearchTerm,
            SelectedDepartmentId > 0 ? SelectedDepartmentId : null);
    }

    private void ClearFilters()
    {
        SearchTerm = string.Empty;
        SelectedDepartmentId = 0;
        ApplyFilters();
    }
}

@page "/enroll"
@using UniversityCourseCatalog.Models
@using UniversityCourseCatalog.Services
@rendermode InteractiveServer
@inject CatalogService CatalogService

<PageTitle>Enrollment Request — University Course Catalog</PageTitle>

<h1 class="mb-3">Enrollment Request</h1>
<p class="text-muted mb-4">Fill out the form below to request enrollment in a course. You will receive a confirmation from the registrar's office.</p>

@if (Submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>Thank you, <strong>@Model.StudentName</strong>. Your enrollment request for
            <strong>@SelectedCourseName</strong> has been received.</p>
        <hr />
        <p class="mb-0">The registrar's office will process your request and contact you at your university email.</p>
    </div>
    <button class="btn btn-outline-primary" @onclick="Reset">Submit Another Request</button>
}
else
{
    <div class="row">
        <div class="col-lg-8">
            <EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="enrollment">
                <DataAnnotationsValidator />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name <span class="text-danger">*</span></label>
                    <InputText id="studentName" class="form-control" @bind-Value="Model.StudentName" />
                    <ValidationMessage For="() => Model.StudentName" />
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                    <InputText id="studentId" class="form-control" @bind-Value="Model.StudentId" placeholder="e.g. STU-12345" />
                    <ValidationMessage For="() => Model.StudentId" />
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                    <InputSelect id="courseId" class="form-select" @bind-Value="Model.CourseId">
                        <option value="0">— Select a course —</option>
                        @foreach (var course in Courses)
                        {
                            <option value="@course.Id">@course.Code — @course.Title (@course.Credits cr)</option>
                        }
                    </InputSelect>
                    <ValidationMessage For="() => Model.CourseId" />
                </div>

                <div class="mb-3">
                    <label for="comments" class="form-label">Comments (optional)</label>
                    <InputTextArea id="comments" class="form-control" rows="3" @bind-Value="Model.Comments" />
                    <ValidationMessage For="() => Model.Comments" />
                </div>

                <button type="submit" class="btn btn-primary">Submit Enrollment Request</button>
            </EditForm>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    private EnrollmentRequest Model { get; set; } = new();
    private List<Course> Courses { get; set; } = new();
    private bool Submitted { get; set; }
    private string SelectedCourseName { get; set; } = string.Empty;

    protected override void OnInitialized()
    {
        Courses = CatalogService.GetCourses();
        if (CourseId.HasValue)
            Model.CourseId = CourseId.Value;
    }

    private void HandleSubmit()
    {
        var course = CatalogService.GetCourse(Model.CourseId);
        SelectedCourseName = course is not null ? $"{course.Code} — {course.Title}" : "Unknown";
        CatalogService.SubmitEnrollmentRequest(Model);
        Submitted = true;
    }

    private void Reset()
    {
        Model = new EnrollmentRequest();
        Submitted = false;
        SelectedCourseName = string.Empty;
    }
}

